  const kalshiSearch = await callMcpSkill({
    toolId: KALSHI_ID,
    toolName: "search_markets",
    args: { query: "Federal Reserve March 2026", status: "open" }
  });

  // 3. Extract Kalshi results, filtering for the Federal Reserve (Fed) specifically
  let kalshiDetails = [];
  let selectedKalshiEvent = null;

  if (kalshiSearch.results && kalshiSearch.results.length > 0) {
